// ============================================================================
// Category-Based Logging System
// ============================================================================
//
// Features:
// - Compile-time zero-overhead for disabled categories
// - Runtime filtering by category and subsystem
// - In-memory telemetry ring buffer (always-on, dump on demand)
// - Session-based log files (no unbounded growth)
// - Structured telemetry API (type-safe, no string parsing)
//
// Categories: Error, Warning, Info, Debug, Performance, Telemetry, Network, Git, UI
// Subsystems: CommitView, DiffView, Sidebar, Clone, Fetch, Push, Checkout, PackParse, etc.
//
// ============================================================================

#include "log_types.h"
#include "tsf_types.h"

// Logging system lifecycle (call from app startup/shutdown)
bool log_system_init();
void log_system_shutdown();

// Runtime filter checks
bool log_category_enabled_runtime(Log::Category cat);
bool log_subsystem_enabled_runtime(Log::Subsystem sub);

// Filter mask control
void log_set_category_mask(uint32_t mask);
void log_set_subsystem_mask(uint32_t mask);
uint32_t log_get_category_mask();
uint32_t log_get_subsystem_mask();

// File logging control
void log_set_file_enabled(bool enabled);
const char* log_get_session_path();

// Timestamp and core write functions
uint64_t log_get_timestamp_us();
void log_write_impl(Log::Category cat, const char* subsystem, const char* fmt, ...);
void log_telemetry_impl(const Log::TelemetryEntry& entry);

// Telemetry access
Log::TelemetryRing* log_get_telemetry_ring();
void log_dump_telemetry_json(const char* path);

// Compile-time category check
#define LOG_CATEGORY_ENABLED(cat) \
    ((static_cast<uint32_t>(Log::Category::cat) & Log::COMPILE_TIME_MASK) != 0)

// Category logging macros (compile-time + runtime filtered)
#define LOG_CAT(cat, ...) \
    do { \
        if constexpr (LOG_CATEGORY_ENABLED(cat)) { \
            if (log_category_enabled_runtime(Log::Category::cat)) { \
                log_write_impl(Log::Category::cat, nullptr, __VA_ARGS__); \
            } \
        } \
    } while(0)

// Debug logging with subsystem (compile-time + runtime filtered)
#define LOG_DEBUG(subsys, ...) \
    do { \
        if constexpr (LOG_CATEGORY_ENABLED(Debug)) { \
            if (log_subsystem_enabled_runtime(Log::Subsystem::subsys)) { \
                log_write_impl(Log::Category::Debug, #subsys, __VA_ARGS__); \
            } \
        } \
    } while(0)

// Convenience macros for common categories
#define LOG_ERROR(...)    LOG_CAT(Error, __VA_ARGS__)
#define LOG_WARN(...)     LOG_CAT(Warning, __VA_ARGS__)
#define LOG_INFO(...)     LOG_CAT(Info, __VA_ARGS__)
#define LOG_PERF(...)     LOG_CAT(Performance, __VA_ARGS__)
#define LOG_NET(...)      LOG_CAT(Network, __VA_ARGS__)
#define LOG_GIT(...)      LOG_CAT(Git, __VA_ARGS__)
#define LOG_UI(...)       LOG_CAT(UI, __VA_ARGS__)

// Legacy compatibility - maps to LOG_INFO
#define LOG(...) LOG_INFO(__VA_ARGS__)
#define LOG_INIT() log_system_init()
#define LOG_CLOSE() log_system_shutdown()

// Structured telemetry macros
#define TELEM_CLONE_PHASE(phase_name, elapsed_ms_val, objects_val, bytes_val) \
    do { \
        if constexpr (LOG_CATEGORY_ENABLED(Telemetry)) { \
            Log::TelemetryEntry e = {}; \
            e.timestamp_us = log_get_timestamp_us(); \
            e.event_type = Log::TelemetryEvent::ClonePhase; \
            e.thread_id = GetCurrentThreadId(); \
            e.data.clone.phase = static_cast<uint32_t>(Log::ClonePhase::phase_name); \
            e.data.clone.elapsed_ms = (elapsed_ms_val); \
            e.data.clone.objects = (objects_val); \
            e.data.clone.bytes = (bytes_val); \
            log_telemetry_impl(e); \
        } \
    } while(0)

#define TELEM_FETCH_OP(op_name, elapsed_ms_val, refs_val, status_val, pack_size_val) \
    do { \
        if constexpr (LOG_CATEGORY_ENABLED(Telemetry)) { \
            Log::TelemetryEntry e = {}; \
            e.timestamp_us = log_get_timestamp_us(); \
            e.event_type = Log::TelemetryEvent::FetchOperation; \
            e.thread_id = GetCurrentThreadId(); \
            e.data.fetch.operation = static_cast<uint32_t>(Log::FetchOp::op_name); \
            e.data.fetch.elapsed_ms = (elapsed_ms_val); \
            e.data.fetch.refs = (refs_val); \
            e.data.fetch.status = (status_val); \
            e.data.fetch.pack_size = (pack_size_val); \
            log_telemetry_impl(e); \
        } \
    } while(0)

#define TELEM_PACK_PARSING(commits_val, trees_val, blobs_val, tags_val, ofs_val, ref_val) \
    do { \
        if constexpr (LOG_CATEGORY_ENABLED(Telemetry)) { \
            Log::TelemetryEntry e = {}; \
            e.timestamp_us = log_get_timestamp_us(); \
            e.event_type = Log::TelemetryEvent::PackParsing; \
            e.thread_id = GetCurrentThreadId(); \
            e.data.pack_parsing.commits = (commits_val); \
            e.data.pack_parsing.trees = (trees_val); \
            e.data.pack_parsing.blobs = (blobs_val); \
            e.data.pack_parsing.tags = (tags_val); \
            e.data.pack_parsing.ofs_delta = (ofs_val); \
            e.data.pack_parsing.ref_delta = (ref_val); \
            log_telemetry_impl(e); \
        } \
    } while(0)

#define TELEM_DELTA(max_depth_val, resolved_val, delta_us, sha_us) \
    do { \
        if constexpr (LOG_CATEGORY_ENABLED(Telemetry)) { \
            Log::TelemetryEntry e = {}; \
            e.timestamp_us = log_get_timestamp_us(); \
            e.event_type = Log::TelemetryEvent::DeltaResolution; \
            e.thread_id = GetCurrentThreadId(); \
            e.data.delta.max_depth = (max_depth_val); \
            e.data.delta.resolved = (resolved_val); \
            e.data.delta.delta_apply_us = (delta_us); \
            e.data.delta.sha_compute_us = (sha_us); \
            log_telemetry_impl(e); \
        } \
    } while(0)

#define TELEM_CACHE(hits_val, misses_val, evictions_val, puts_val, evicted_bytes_val) \
    do { \
        if constexpr (LOG_CATEGORY_ENABLED(Telemetry)) { \
            Log::TelemetryEntry e = {}; \
            e.timestamp_us = log_get_timestamp_us(); \
            e.event_type = Log::TelemetryEvent::ObjectCache; \
            e.thread_id = GetCurrentThreadId(); \
            e.data.cache.hits = (hits_val); \
            e.data.cache.misses = (misses_val); \
            e.data.cache.evictions = (evictions_val); \
            e.data.cache.puts = (puts_val); \
            e.data.cache.evicted_bytes = (evicted_bytes_val); \
            log_telemetry_impl(e); \
        } \
    } while(0)

// Git remote configuration
struct GitRemote {
    char name[Git::MAX_REF_NAME];        // e.g., "origin"
    char url[Remote::MAX_URL];           // e.g., "https://github.com/user/repo.git"
    char fetch_refspec[256];             // e.g., "+refs/heads/*:refs/remotes/origin/*"
};

// Remote reference (from server)
struct GitRemoteRef {
    char name[Git::MAX_REF_NAME];        // e.g., "refs/heads/main"
    char sha[Git::SHA1_HEX_SIZE + 1];    // Target SHA
    char peeled[Git::SHA1_HEX_SIZE + 1]; // Peeled SHA (for annotated tags)
    char symref_target[Git::MAX_REF_NAME]; // For symbolic refs like HEAD
};

// Credential storage
struct GitCredential {
    char protocol[16];                   // "https" or "http"
    char host[256];                      // "github.com"
    char username[128];
    char password[512];                  // Or token
};

// Fetch operation phases
enum class FetchPhase {
    Idle = 0,
    Connecting,
    Authenticating,
    Negotiating,
    Receiving,
    ResolvingDeltas,
    Updating,
    Complete,
    Failed,
    Cancelled
};

// Base progress struct with common fields (atomic for thread-safe access)
struct BaseProgress {
    std::atomic<int64_t> start_time_ms{0};
    std::atomic<bool> cancel_requested{false};
    std::atomic<uint32_t> generation{0};
};

// Fetch progress (atomic for thread-safe access)
struct FetchProgress {
    std::atomic<FetchPhase> phase{FetchPhase::Idle};
    std::atomic<uint64_t> objects_done{0};
    std::atomic<uint64_t> objects_total{0};
    std::atomic<uint64_t> bytes_received{0};
    std::atomic<uint64_t> bytes_total{0};
    std::atomic<uint64_t> deltas_done{0};    // Delta resolution progress
    std::atomic<uint64_t> deltas_total{0};   // Total deltas to resolve
    BaseProgress base;
};

// Fetch mode - determines which refs to fetch
enum class FetchMode {
    QuickSync,   // Current branch only (fastest)
    Smart,       // Priority refs: current + visible + recent (default)
    Full         // All refs (slowest but complete)
};

// Fetch options
struct FetchOptions {
    FetchMode mode = FetchMode::Smart;   // Which refs to fetch
    bool prune = false;                  // Remove stale remote-tracking refs
    int depth = 0;                       // Shallow clone depth (0 = full)
    void (*progress_callback)(const FetchProgress* progress, void* user_data) = nullptr;
    void* progress_user_data = nullptr;
};

// Fetch result
struct FetchResult {
    bool success = false;
    char error_message[Remote::MAX_ERROR_MSG] = {0};
    size_t refs_updated = 0;
    size_t objects_received = 0;
    uint64_t bytes_received = 0;
    int64_t duration_ms = 0;
};

// Push operation phases
enum class PushPhase {
    Idle = 0,
    Connecting,
    Authenticating,
    Negotiating,      // Determining what objects to send
    Counting,         // Counting objects to pack
    Compressing,      // Building pack file
    Writing,          // Sending pack to server
    UpdatingRefs,     // Server updating refs
    Complete,
    Failed,
    Rejected,         // Non-fast-forward rejection
    Cancelled
};

// Push progress (atomic for thread-safe access)
struct PushProgress {
    std::atomic<PushPhase> phase{PushPhase::Idle};
    std::atomic<uint64_t> objects_done{0};
    std::atomic<uint64_t> objects_total{0};
    std::atomic<uint64_t> bytes_sent{0};
    std::atomic<uint64_t> bytes_total{0};
    BaseProgress base;
};

// Push result status per ref
enum class PushRefStatus {
    Success,          // "ok refname"
    Rejected,         // "ng refname reason"
    NonFastForward,   // Non-fast-forward rejection
    Error             // Protocol error
};

// Push result for a single ref
struct PushRefResult {
    char ref_name[Git::MAX_REF_NAME];
    char old_sha[Git::SHA1_HEX_SIZE + 1];
    char new_sha[Git::SHA1_HEX_SIZE + 1];
    PushRefStatus status;
    char error_message[256];
};

// Overall push result
struct PushResult {
    bool success = false;
    char error_message[Remote::MAX_ERROR_MSG] = {0};
    PushRefResult ref_results[16];
    size_t ref_count = 0;
    size_t objects_sent = 0;
    uint64_t bytes_sent = 0;
    int64_t duration_ms = 0;
};

// Push options
struct PushOptions {
    bool force = false;              // Allow non-fast-forward
    bool dry_run = false;            // Don't actually push
    bool set_upstream = false;       // Set tracking branch
    void (*progress_callback)(const PushProgress* progress, void* user_data) = nullptr;
    void* progress_user_data = nullptr;
};

// Object to send in a push operation (for pack generation)
struct ObjectToSend {
    char sha[Git::SHA1_HEX_SIZE + 1];
    int type;           // Git::OBJ_COMMIT, OBJ_TREE, OBJ_BLOB
    size_t size;        // Uncompressed size
};

// Pull operation phases
enum class PullPhase {
    Idle = 0,
    Fetching,           // Running git_fetch internally
    CheckingFastForward,// Verifying fast-forward is possible
    UpdatingWorkdir,    // Writing files to working directory
    UpdatingIndex,      // Rewriting .git/index
    UpdatingRefs,       // Updating branch ref
    Complete,
    Failed,
    Cancelled,
    NotFastForward,     // Local commits ahead - fast-forward not possible
    DirtyWorkdir        // Uncommitted changes - cannot pull
};

// Pull progress (atomic for thread-safe access)
struct PullProgress {
    std::atomic<PullPhase> phase{PullPhase::Idle};
    std::atomic<uint64_t> files_done{0};      // Files updated in checkout
    std::atomic<uint64_t> files_total{0};     // Total files to update
    BaseProgress base;

    // Nested fetch progress (copy from fetch operation)
    std::atomic<FetchPhase> fetch_phase{FetchPhase::Idle};
    std::atomic<uint64_t> fetch_bytes{0};
};

// Pull result
struct PullResult {
    bool success = false;
    char error_message[Remote::MAX_ERROR_MSG] = {0};
    char old_sha[Git::SHA1_HEX_SIZE + 1] = {0};   // Previous HEAD SHA
    char new_sha[Git::SHA1_HEX_SIZE + 1] = {0};   // New HEAD SHA after pull
    size_t files_updated = 0;                      // Files changed in working directory
    size_t files_added = 0;                        // New files created
    size_t files_deleted = 0;                      // Files removed
    int64_t duration_ms = 0;
    int commits_pulled = 0;                        // How many commits we advanced

    // Auto-stash information
    bool used_auto_stash = false;                  // True if changes were auto-stashed
    bool stash_apply_had_conflicts = false;        // True if stash re-apply had conflicts
    char stash_sha[Git::SHA1_HEX_SIZE + 1] = {0}; // SHA of auto-created stash (if any)
};

// Pull options
struct PullOptions {
    bool auto_stash = false;             // Auto-stash dirty changes before pull
    bool stash_include_untracked = false; // Include untracked files in auto-stash
    void (*progress_callback)(const PullProgress* progress, void* user_data) = nullptr;
    void* progress_user_data = nullptr;
};

