// ============================================================================

// Row type for side-by-side pairing
enum class SideBySideRowType : uint8_t {
    Context,        // Same line on both sides (unchanged)
    Modified,       // Different content, paired by similarity
    AddedOnly,      // Right side only (left is placeholder)
    RemovedOnly     // Left side only (right is placeholder)
};

// A single row in side-by-side view (pairs left/right lines)
struct SideBySidePair {
    DiffLine* left_line;       // Line on left pane (nullptr = placeholder)
    DiffLine* right_line;      // Line on right pane (nullptr = placeholder)
    float y_offset;            // Absolute Y position from content top
    SideBySideRowType row_type;
};

// Index for O(1) visible range calculation in side-by-side mode
struct SideBySideLineIndex {
    SideBySidePair* pairs;     // Array of paired rows
    size_t pair_count;         // Number of rows
    size_t capacity;           // Allocated capacity
    float total_height;        // Total content height
    float line_height;         // Height per row (cached)

    // Build index from FileDiff using similarity-based pairing
    void build_from_diff(const FileDiff* diff, float lh);

    // Clear and deallocate
    void clear();
    void destroy();

    // O(1) visible range calculation
    size_t first_visible_index(float scroll_y) const {
        if (pair_count == 0 || line_height <= 0) return 0;
        size_t idx = static_cast<size_t>(scroll_y / line_height);
        return (idx < pair_count) ? idx : pair_count - 1;
    }

    size_t pairs_in_viewport(float viewport_height) const {
        if (line_height <= 0) return 0;
        return static_cast<size_t>(viewport_height / line_height) + 2;  // +2 for partial rows
    }
};

// Compute similarity between two lines (0.0 = completely different, 1.0 = identical)
float diff_line_similarity(const char* old_line, const char* new_line);

// ============================================================================
// UTF-8 / Wide Character Conversion Utilities
// ============================================================================

// Convert UTF-8 string to wide character string (truncates if buffer too small)
// Returns the number of wide characters written (including null terminator),
// or 0 on failure.
static inline size_t utf8_to_wide_n(const char* src, wchar_t* dest, size_t dest_size) {
    if (!src || !dest || dest_size == 0) return 0;
    if (src[0] == '\0') {
        dest[0] = L'\0';
        return 1;
    }
    int result = MultiByteToWideChar(CP_UTF8, 0, src, -1, dest, static_cast<int>(dest_size));
    return (result > 0) ? static_cast<size_t>(result) : 0;
}

// Convert UTF-8 string to wide character string (with truncation detection)
// Returns true if conversion succeeded and fit exactly, false if truncation occurred
// or on error. On false, dest is set to truncated result.
static inline bool utf8_to_wide(const char* src, wchar_t* dest, size_t dest_size) {
    if (!src || !dest || dest_size == 0) return false;
    if (src[0] == '\0') {
        dest[0] = L'\0';
        return true;
    }

    // First, query the required size (not including null terminator)
    int required = MultiByteToWideChar(CP_UTF8, 0, src, -1, nullptr, 0);
    if (required <= 0) return false;

    // Check if it fits (required includes null terminator)
    if (static_cast<size_t>(required) > dest_size) {
        // Truncate: convert with available space
        MultiByteToWideChar(CP_UTF8, 0, src, -1, dest, static_cast<int>(dest_size));
        // Ensure null termination
        dest[dest_size - 1] = L'\0';
        return false;
    }

    // Convert with exact fit
    int result = MultiByteToWideChar(CP_UTF8, 0, src, -1, dest, static_cast<int>(dest_size));
    return (result > 0);
}

// Convert wide character string to UTF-8 string
// Returns number of bytes written including null terminator, or 0 on failure.
static inline size_t wide_to_utf8(const wchar_t* src, char* dest, size_t dest_size) {
    if (!src || !dest || dest_size == 0) return 0;
    if (src[0] == L'\0') {
        dest[0] = '\0';
        return 1;
    }
    int result = WideCharToMultiByte(CP_UTF8, 0, src, -1, dest, static_cast<int>(dest_size), nullptr, nullptr);
    if (result <= 0) {
        dest[0] = '\0';
        return 0;
    }
    return static_cast<size_t>(result);
}

