// Identifies which implementation a SHA1_CTX is using. Stored as uint8_t to keep
// SHA1_CTX compact; values are intentionally chosen so 0 = uninitialized (zeroed).
namespace SHA1Backend {
    constexpr uint8_t Uninitialized = 0;
    constexpr uint8_t ShaNI         = 1;  // x64 SHA-NI fast path (currently unused by streaming API)
    constexpr uint8_t BCrypt        = 2;  // Windows BCrypt provider
    constexpr uint8_t Software      = 3;  // Portable C fallback
    constexpr uint8_t Poisoned      = 0xFF; // BCrypt mid-stream error; emit zeroes and bail
}

// Streaming SHA-1 context for incremental hashing (avoids temp buffer allocation)
struct SHA1_CTX {
    alignas(64) uint8_t buffer[64];   // Partial block buffer (cache-line aligned)
    uint32_t state[5];                // H0-H4 hash state (software fallback)
    uint64_t total_bytes;             // Total bytes processed
    uint8_t buffer_len;               // Bytes in partial buffer (0-63)
    uint8_t backend;                  // See SHA1Backend:: constants
    bool finalized;                   // Defensive: prevent update after final
    void* bcrypt_handle;              // BCrypt hash handle (ARM64)
};

