    const char* id;              // Unique identifier: "git.stageAll"
    const wchar_t* name;         // Display name: L"Stage All"
    PaletteCategory category;    // Category for grouping
    const char* shortcut;        // Display shortcut: "Ctrl+A" (nullptr if none)
    bool (*is_available)();      // Context check function (nullptr = always available)
    void (*execute)();           // Action function
