struct FuzzyMatchResult {
    int score;                   // Total match score (0 = no match)
    uint64_t match_mask;         // Bitmask of matched character positions (up to 64 chars)
    bool matched;                // True if query matches target
};

// Palette result item (unified across all result types)
enum class PaletteResultType {
    Command,
    File,
    Branch,
    Commit,
    Remote
};

struct PaletteResult {
    PaletteResultType type;
    int score;                   // Fuzzy match score for sorting
    uint64_t match_mask;         // For highlighting matched chars

    // File status for palette display
    enum class FileStatus { Modified = 0, Added, Deleted, Renamed, Untracked };

    // Type-specific data
    union {
        const PaletteCommand* command;
        struct {
            const char* utf8_path;   // UTF-8 path for git commands
            bool is_staged;
            FileStatus status;       // File status (M/A/D/R/?)
        } file;
        const GitRef* branch;
        size_t commit_index;     // Index into g_history
        const char* remote_name; // Remote name (UTF-8)
    };

    // Display text (points into source data, do not free)
    const wchar_t* display_text;
    const char* shortcut;        // For commands (nullptr for others)
    bool selected;               // Multi-select state
};

