// ============================================================================
// Frame-Driven Animation Timing
// ============================================================================

// High-precision frame clock for animation timing
// Uses QueryPerformanceCounter for accurate delta time calculation
// and DWM timing info for refresh rate detection
struct FrameClock {
    LARGE_INTEGER frequency;        // QPC frequency (ticks per second)
    LARGE_INTEGER last_frame_time;  // QPC value at last update
    float delta_time;               // Seconds since last frame
    float refresh_period;           // Monitor refresh period in seconds
    bool initialized;

    // Track last refresh check time for periodic re-detection (VRR/monitor changes)
    LARGE_INTEGER last_refresh_check;
    static constexpr float REFRESH_CHECK_INTERVAL = 5.0f;  // Re-check every 5 seconds

    void init();
    float update();
    float detect_refresh_period();
    void maybe_update_refresh_rate();
};

extern FrameClock g_frame_clock;

// ============================================================================
// Animation Scheduler
// ============================================================================

// Animation scheduler: tracks active animations for continuous render requests
// When animations are active, render_frame() calls InvalidateRect() to keep rendering
// This makes the system fully self-driving: no timer polling required
struct AnimationScheduler {
    std::atomic<int> active_count{0};
    HWND hwnd{nullptr};  // Window handle for InvalidateRect calls

    // Initialize with window handle (call from WM_CREATE)
    void init(HWND window_handle) {
        hwnd = window_handle;
    }

    // Called when an animation starts (target changes from settled state)
    void animation_started() {
        int prev = active_count.fetch_add(1, std::memory_order_relaxed);
        // Kick the render loop when first animation starts
        // This ensures the loop begins even without user input triggering a paint
        if (prev == 0 && hwnd) {
            InvalidateRect(hwnd, nullptr, FALSE);
        }
    }

    // Called when an animation completes (settled at target)
    void animation_ended() {
        int prev = active_count.fetch_sub(1, std::memory_order_relaxed);
#ifdef GITSMARTER_DEBUG
        // Debug warning: this indicates a bug in animation start/end accounting
        if (prev <= 0) {
            LOG("WARNING: animation_ended() called when active_count was %d (underflow)", prev);
        }
#endif
        // Safety: prevent underflow (shouldn't happen but be defensive)
        if (prev <= 0) {
            active_count.store(0, std::memory_order_relaxed);
        }
    }

    // Check if any animations are active
    bool needs_continuous_render() const {
        return active_count.load(std::memory_order_relaxed) > 0;
    }

    // Reset for testing scenarios
    void reset() {
        active_count.store(0, std::memory_order_relaxed);
    }
};

extern AnimationScheduler g_animation_scheduler;

// ============================================================================
// Spring Animation (Windows Composition-style closed-form solution)
// ============================================================================
//
// Analytical solution for damped harmonic motion: a + 2ωζv + ω²x = 0
// Computes exact position/velocity for any time step without integration errors.
//
// Benefits over Euler integration:
// - Frame-rate independent (same results at 30, 60, or 144 fps)
// - No energy drift or accumulation
// - Stable with large dt values (e.g., debugger pause)
// - Deterministic (same inputs = same outputs)

struct SpringCoefficients {
    float posPosCoef;  // newPos contribution from oldPos
    float posVelCoef;  // newPos contribution from oldVel
    float velPosCoef;  // newVel contribution from oldPos
    float velVelCoef;  // newVel contribution from oldVel
};

// Compute coefficients for a given dt, angularFrequency, and dampingRatio.
// Can be cached if dt is fixed (e.g., fixed timestep physics).
SpringCoefficients calc_spring_coefficients(float dt, float angularFrequency, float dampingRatio);

// Update spring state using precomputed coefficients.
// Returns true if still animating.
bool spring_update(float& value, float& velocity, float target,
                   const SpringCoefficients& c,
                   float settleThreshold = 0.001f,
                   float velocityThreshold = 0.01f);

// Windows-style API: period (seconds) and damping ratio
// - period: Time for one oscillation (100-150ms typical for UI)
// - dampingRatio: 0.5-0.7 for visible bounce, 1.0 for no overshoot
bool spring_update_windows_style(float& value, float& velocity, float target, float dt,
                                  float period, float dampingRatio,
                                  float settleThreshold = 0.001f,
                                  float velocityThreshold = 0.01f);

// Legacy compatibility: stiffness/damping style (assumes mass = 1)
bool spring_update_stiffness_damping(float& value, float& velocity, float target, float dt,
                                      float stiffness, float damping,
                                      float settleThreshold = 0.001f,
                                      float velocityThreshold = 0.01f);

